namespace sv_8fd44b137f9140e799c39c1c0d213fd1.Models;

public class Product
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public int Quantity { get; set; }
    public decimal UnitPrice { get; set; }
    public string Category { get; set; } = string.Empty;
}

using sv_8fd44b137f9140e799c39c1c0d213fd1.Models;

namespace sv_8fd44b137f9140e799c39c1c0d213fd1.Services;

public class InventoryService
{
    private readonly List<Product> _products = new()
    {
        new Product { Id = 1, Name = "Wireless Mouse", Quantity = 150, UnitPrice = 29.99m, Category = "Electronics" },
        new Product { Id = 2, Name = "Cotton T-Shirt", Quantity = 300, UnitPrice = 14.95m, Category = "Clothing" },
        new Product { Id = 3, Name = "Organic Almonds", Quantity = 80, UnitPrice = 8.49m, Category = "Food" },
        new Product { Id = 4, Name = "USB-C Cable", Quantity = 500, UnitPrice = 9.99m, Category = "Electronics" },
        new Product { Id = 5, Name = "Winter Jacket", Quantity = 45, UnitPrice = 89.00m, Category = "Clothing" },
        new Product { Id = 6, Name = "Notebook & Pen Set", Quantity = 200, UnitPrice = 5.50m, Category = "Other" }
    };

    private readonly Lock _lock = new();

    public Task<List<Product>> GetAllAsync()
    {
        lock (_lock)
        {
            var copy = _products.Select(p => new Product
            {
                Id = p.Id,
                Name = p.Name,
                Quantity = p.Quantity,
                UnitPrice = p.UnitPrice,
                Category = p.Category
            }).ToList();

            return Task.FromResult(copy);
        }
    }

    public Task UpdateAsync(Product product)
    {
        lock (_lock)
        {
            var existing = _products.FirstOrDefault(p => p.Id == product.Id)
                ?? throw new InvalidOperationException($"Product with Id {product.Id} not found.");

            existing.Name = product.Name;
            existing.Quantity = product.Quantity;
            existing.UnitPrice = product.UnitPrice;
            existing.Category = product.Category;
        }

        return Task.CompletedTask;
    }
}

@page "/inventory"
@rendermode InteractiveServer
@using sv_8fd44b137f9140e799c39c1c0d213fd1.Models
@using sv_8fd44b137f9140e799c39c1c0d213fd1.Services
@inject InventoryService InventoryService

<h1>Inventory</h1>

@if (_products is null)
{
    <p>Loading...</p>
}
else if (_products.Count == 0)
{
    <p>No products found.</p>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Name</th>
                <th>Quantity</th>
                <th>Unit Price</th>
                <th>Category</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var product in _products)
            {
                <tr @key="product.Id">
                    @if (_editingId == product.Id)
                    {
                        <td>
                            <input class="form-control" @bind="_editName" />
                            @if (_errors.ContainsKey("Name"))
                            {
                                <span class="text-danger">@_errors["Name"]</span>
                            }
                        </td>
                        <td>
                            <input type="number" class="form-control" @bind="_editQuantity" />
                            @if (_errors.ContainsKey("Quantity"))
                            {
                                <span class="text-danger">@_errors["Quantity"]</span>
                            }
                        </td>
                        <td>
                            <input type="number" step="0.01" class="form-control" @bind="_editUnitPrice" />
                            @if (_errors.ContainsKey("UnitPrice"))
                            {
                                <span class="text-danger">@_errors["UnitPrice"]</span>
                            }
                        </td>
                        <td>
                            <select class="form-select" @bind="_editCategory">
                                <option value="">-- Select --</option>
                                @foreach (var cat in Categories)
                                {
                                    <option value="@cat">@cat</option>
                                }
                            </select>
                            @if (_errors.ContainsKey("Category"))
                            {
                                <span class="text-danger">@_errors["Category"]</span>
                            }
                        </td>
                        <td>
                            <button class="btn btn-success btn-sm" @onclick="SaveAsync">Save</button>
                            <button class="btn btn-secondary btn-sm" @onclick="Cancel">Cancel</button>
                        </td>
                    }
                    else
                    {
                        <td>@product.Name</td>
                        <td>@product.Quantity</td>
                        <td>@product.UnitPrice.ToString("C")</td>
                        <td>@product.Category</td>
                        <td>
                            <button class="btn btn-primary btn-sm" @onclick="() => Edit(product)">Edit</button>
                        </td>
                    }
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private static readonly string[] Categories = { "Electronics", "Clothing", "Food", "Other" };

    private List<Product>? _products;
    private int? _editingId;

    private string _editName = string.Empty;
    private int _editQuantity;
    private decimal _editUnitPrice;
    private string _editCategory = string.Empty;
    private Dictionary<string, string> _errors = new();

    protected override async Task OnInitializedAsync()
    {
        _products = await InventoryService.GetAllAsync();
    }

    private void Edit(Product product)
    {
        _editingId = product.Id;
        _editName = product.Name;
        _editQuantity = product.Quantity;
        _editUnitPrice = product.UnitPrice;
        _editCategory = product.Category;
        _errors.Clear();
    }

    private void Cancel()
    {
        _editingId = null;
        _errors.Clear();
    }

    private async Task SaveAsync()
    {
        if (!Validate())
            return;

        var product = _products!.First(p => p.Id == _editingId);
        product.Name = _editName.Trim();
        product.Quantity = _editQuantity;
        product.UnitPrice = _editUnitPrice;
        product.Category = _editCategory;

        await InventoryService.UpdateAsync(product);
        _editingId = null;
    }

    private bool Validate()
    {
        _errors.Clear();

        if (string.IsNullOrWhiteSpace(_editName))
            _errors["Name"] = "Name is required.";

        if (_editQuantity < 0 || _editQuantity > 9999)
            _errors["Quantity"] = "Quantity must be 0–9999.";

        if (_editUnitPrice <= 0)
            _errors["UnitPrice"] = "Price must be greater than 0.";

        if (string.IsNullOrWhiteSpace(_editCategory))
            _errors["Category"] = "Category is required.";

        return _errors.Count == 0;
    }
}

